insert into omp_drama values (1010003, '1', '', '0', '', '1', '1', '1', '0', 31, 1);
insert into omp_drama values (1010004, '', '', '', '', '', '1', '', '', 93, 1);
insert into omp_drama values (1010005, 'vo_omp_7001_000', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010006, 'ウヅキ、大丈夫？\\n夜営続きで疲れてない？', '', '10', '', '', '112511', '1', '1', 11, 1);
insert into omp_drama values (1010007, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010008, 'omp_idle_worry', '', '1', '', '0', '112511', '', '', 3, 1);
insert into omp_drama values (1010009, 'omp_talk_joy1', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010010, 'vo_omp_7001_001', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010011, 'はい、大丈夫です！\\nみんなと一緒に旅をするの\\nとっても楽しいですし', '', '10', '', '', '112411', '1', '1', 11, 1);
insert into omp_drama values (1010012, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010013, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010014, 'omp_talk_normal', '', '1', '', '0', '112511', '', '', 3, 1);
insert into omp_drama values (1010015, 'vo_omp_7001_002', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010016, 'そっか\\nウヅキはどんなときも楽しそうだよね', '', '10', '', '', '112511', '1', '1', 11, 1);
insert into omp_drama values (1010017, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010018, 'omp_idle_normal', '', '1', '', '0', '112511', '', '', 3, 1);
insert into omp_drama values (1010019, 'omp_talk_sad', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010020, 'vo_omp_7001_003', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010021, 'もしかして…\\nリンちゃんは楽しくないですか？', '', '10', '', '', '112411', '1', '1', 11, 1);
insert into omp_drama values (1010022, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010023, 'omp_idle_sad', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010024, 'omp_surprise', '0.1', '0', '', '0', '112511', '1', 'omp_idle_surprise1', 3, 1);
insert into omp_drama values (1010025, 'vo_omp_7001_004', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010026, 'えっ？\u3000どうして？\\nそんなことないよ\\n私も…すごく楽しい', '', '10', '', '', '112511', '1', '1', 11, 1);
insert into omp_drama values (1010027, '1', '', '', '', '', '2.5', '', '', 93, 1);
insert into omp_drama values (1010028, 'omp_talk_normal', '', '1', '', '0.2', '112511', '', '', 3, 1);
insert into omp_drama values (1010029, '', '', '', '', '', '1010026', '', '', 91, 1);
insert into omp_drama values (1010030, 'omp_idle_normal', '', '1', '', '0', '112511', '', '', 3, 1);
insert into omp_drama values (1010031, 'omp_talk_joy2', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010032, 'vo_omp_7001_005', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010033, 'えへへっ♪\\nそれなら安心してください！\\nリンちゃんが楽しいなら\\n私も楽しいですから！', '', '10', '', '', '112411', '1', '1', 11, 1);
insert into omp_drama values (1010034, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010035, '0', '', '1', '', '', '112511', '', '', 4, 1);
insert into omp_drama values (1010036, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 1);
insert into omp_drama values (1010037, 'omp_idle_normal', '', '1', '', '0', '112511', '', '', 3, 1);
insert into omp_drama values (1010038, 'vo_omp_7001_006', '', '0', '', '', 'vo_omp_7001', '', '0', 21, 1);
insert into omp_drama values (1010039, '心配してたつもりなのに…\\n私が励まされちゃった\\nウヅキはやっぱりすごいな…', '', '10', '', '', '112511', '1', '1', 11, 1);
insert into omp_drama values (1010040, '', '', '', '', '', '0', '', '', 91, 1);
insert into omp_drama values (1010041, '', '', '', '', '', '0.4', '', '', 93, 1);
