insert into omp_drama values (1020005, '', '', '', '', '', '1', '', '', 93, 2);
insert into omp_drama values (1020006, 'vo_omp_7002_000', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020007, 'ペコリーヌちゃんの魔物料理、\\n美味しかったですね♪', '', '10', '', '', '112411', '1', '1', 11, 2);
insert into omp_drama values (1020008, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020009, '0', '', '', '', '', '112411', '', '', 4, 2);
insert into omp_drama values (1020010, 'omp_idle_normal', '', '1', '', '0', '112411', '', '', 3, 2);
insert into omp_drama values (1020011, 'omp_talk_joy1', '', '1', '', '0', '112611', '', '', 3, 2);
insert into omp_drama values (1020012, 'vo_omp_7002_001', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020013, 'うん！\u3000美味しかったし\\n冒険の醍醐味って感じがして…\\nすごい経験しちゃったなって！', '', '10', '', '', '112611', '1', '1', 11, 2);
insert into omp_drama values (1020014, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020015, 'omp_idle_joy1', '', '1', '', '0', '112611', '', '', 3, 2);
insert into omp_drama values (1020016, 'omp_talk_surprise1', '', '1', '', '0', '112411', '', '', 3, 2);
insert into omp_drama values (1020017, 'vo_omp_7002_002', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020018, 'でも不思議ですよね\\nあんな見た目の魔物が\\nご馳走に変身しちゃうなんて！', '', '10', '', '', '112411', '1', '1', 11, 2);
insert into omp_drama values (1020019, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020020, '1', '', '', '', '', '112411', '', '', 4, 2);
insert into omp_drama values (1020021, 'omp_idle_surprise1', '', '1', '', '0', '112411', '', '', 3, 2);
insert into omp_drama values (1020022, 'omp_talk_normal', '', '1', '', '0', '112511', '', '', 3, 2);
insert into omp_drama values (1020023, 'vo_omp_7002_003', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020024, '全然想像できない味だったね\\nいい意味で', '', '10', '', '', '112511', '1', '1', 11, 2);
insert into omp_drama values (1020025, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020026, 'omp_talk_sad', '', '1', '', '0', '112511', '', '', 3, 2);
insert into omp_drama values (1020027, 'vo_omp_7002_004', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020028, 'でも魔物が調理されてるところは\\nまあ、何て言うか…', '', '10', '', '', '112511', '1', '1', 11, 2);
insert into omp_drama values (1020029, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020030, 'omp_idle_sad', '', '1', '', '0', '112511', '', '', 3, 2);
insert into omp_drama values (1020031, 'omp_talk_bitter', '', '1', '', '0', '112411', '', '', 3, 2);
insert into omp_drama values (1020032, 'vo_omp_7002_005', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020033, '…す、すごかったですよね', '', '10', '', '', '112411', '1', '1', 11, 2);
insert into omp_drama values (1020034, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020035, 'omp_idle_bitter', '', '1', '', '0', '112411', '', '', 3, 2);
insert into omp_drama values (1020036, 'omp_talk_joy1', '', '1', '', '0', '112611', '', '', 3, 2);
insert into omp_drama values (1020037, 'vo_omp_7002_006', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020038, '魔物料理は、おペコさんに\\nまるっとお任せしちゃった方が\\nいいかも。あはは～', '', '10', '', '', '112611', '1', '1', 11, 2);
insert into omp_drama values (1020039, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020040, 'omp_idle_joy1', '', '1', '', '0', '112611', '', '', 3, 2);
insert into omp_drama values (1020041, 'omp_talk_bitter', '', '1', '', '0', '112511', '', '', 3, 2);
insert into omp_drama values (1020042, 'vo_omp_7002_007', '', '0', '', '', 'vo_omp_7002', '', '0', 21, 2);
insert into omp_drama values (1020043, '冒険って、奥が深いね…', '', '10', '', '', '112511', '1', '1', 11, 2);
insert into omp_drama values (1020044, '', '', '', '', '', '0', '', '', 91, 2);
insert into omp_drama values (1020045, '', '', '', '', '', '0.4', '', '', 93, 2);
insert into omp_drama values (1030001, '112411', '0', '1500', 'omp_talk_joy1', '1.8', '1', '-190', '-140', 1, 3);
insert into omp_drama values (1030002, '112611', '1', '1500', 'omp_idle_normal', '1.8', '1', '-190', '140', 1, 3);
