insert into omp_drama values (1030004, '', '', '', '', '', '1', '', '', 93, 3);
insert into omp_drama values (1030005, 'vo_omp_7003_000', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030006, 'ミオちゃん！\\nこのあたりっていろいろな\\n魔物がいて楽しいですね！', '', '10', '', '', '112411', '1', '1', 11, 3);
insert into omp_drama values (1030007, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030008, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030009, 'omp_psn_19', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030010, 'vo_omp_7003_001', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030011, 'た、楽しいかな～？', '', '10', '', '', '112611', '1', '1', 11, 3);
insert into omp_drama values (1030012, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030013, 'omp_psn_18', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030014, 'omp_talk_joy1', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030015, 'vo_omp_7003_002', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030016, '怖い魔物もたくさんいますけど\\n探せばぴにゃこら太さんや\\nプチグリフォンさんみたいに\\nかわいい魔物もいると思うんですよね！', '', '10', '', '', '112411', '1', '1', 11, 3);
insert into omp_drama values (1030017, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030018, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030019, 'omp_talk_joy1', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030020, 'vo_omp_7003_003', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030021, 'そういうことか\\nいや、ちょっとまって、しまむー\\nプチグリフォンはかわいいかもだけど\\nぴにゃこら太、かわいいかな～？', '', '10', '', '', '112611', '1', '1', 11, 3);
insert into omp_drama values (1030022, '1', '', '', '', '', '1.5', '', '', 93, 3);
insert into omp_drama values (1030023, 'omp_psn_19', '', '1', '', '0.2', '112611', '', '', 3, 3);
insert into omp_drama values (1030024, '', '', '', '', '', '1030021', '', '', 91, 3);
insert into omp_drama values (1030025, 'omp_psn_18', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030026, 'omp_talk_joy1', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030027, 'vo_omp_7003_004', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030028, 'かわいいですよ～\\n私たちの歌で、たくさんの\\nぴにゃこら太さんを\\n集められませんかね？', '', '10', '', '', '112411', '1', '1', 11, 3);
insert into omp_drama values (1030029, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030030, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030031, 'omp_psn_19', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030032, 'vo_omp_7003_005', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030033, 'いやー、どうだろう\\nぴにゃこら太って\\nオンリーワンみたいなところあるし…\\nむしろオンリーワンであってほしいし…', '', '10', '', '', '112611', '1', '1', 11, 3);
insert into omp_drama values (1030034, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030035, 'omp_psn_18', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030036, 'omp_talk_joy2', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030037, 'vo_omp_7003_006', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030038, 'あっ、たしかにそうですね！\\nまずは目の前のぴにゃこら太さんに\\n認めてもらわなきゃですし♪', '', '10', '', '', '112411', '1', '1', 11, 3);
insert into omp_drama values (1030039, '', '', '', '', '', '0', '', '', 91, 3);
insert into omp_drama values (1030040, 'omp_psn_20', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030041, 'omp_talk_sad', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030042, 'vo_omp_7003_007', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030043, 'そういうことじゃないんだけど…\\n集めるのあきらめてくれたなら\\nまぁ、いっか！\\nその調子で頑張ってこう、しまむー！', '', '10', '', '', '112611', '1', '1', 11, 3);
insert into omp_drama values (1030044, '1', '', '', '', '', '6', '', '', 93, 3);
insert into omp_drama values (1030045, 'omp_talk_joy2', '', '1', '', '0.2', '112611', '', '', 3, 3);
insert into omp_drama values (1030046, '', '', '', '', '', '1030043', '', '', 91, 3);
insert into omp_drama values (1030047, 'omp_idle_joy2', '', '1', '', '0', '112611', '', '', 3, 3);
insert into omp_drama values (1030048, 'omp_talk_joy2', '', '1', '', '0', '112411', '', '', 3, 3);
insert into omp_drama values (1030049, 'vo_omp_7003_008', '', '0', '', '', 'vo_omp_7003', '', '0', 21, 3);
insert into omp_drama values (1030050, 'はい！\\n一緒に頑張りましょう！', '', '10', '', '', '112411', '1', '1', 11, 3);
insert into omp_drama values (1030051, '', '', '', '', '', '0', '', '', 91, 3);
