insert into omp_drama values (1040006, 'vo_omp_7004_000', '', '0', '', '', 'vo_omp_7004', '', '0', 21, 4);
insert into omp_drama values (1040007, 'せっかくですから\\nわたしたちもアイドルを\\nしてみませんか？', '', '10', '', '', '105831', '1', '1', 11, 4);
