insert into omp_drama values (1040012, 'アイドルユニット\\n【美食殿】でございますね\\nとても楽しそうです', '', '10', '', '', '105931', '1', '1', 11, 4);
insert into omp_drama values (1040013, '', '', '', '', '', '0', '', '', 91, 4);
insert into omp_drama values (1040014, '0', '', '', '', '', '105931', '', '', 4, 4);
