insert into omp_drama values (1040018, 'えっ！？\u3000ホントに…！？\\nじゃ、じゃなくて\\nバカじゃないのあんたたち！？', '', '10', '', '', '106031', '1', '1', 11, 4);
insert into omp_drama values (1040019, '1', '', '', '', '', '2', '', '', 93, 4);
