insert into omp_drama values (1040023, 'vo_omp_7004_003', '', '0', '', '', 'vo_omp_7004', '', '0', 21, 4);
insert into omp_drama values (1040024, 'あの３人を見て\\nアイドルがどれだけ大変か\\n分かんなかったっての？', '', '10', '', '', '106031', '1', '1', 11, 4);
insert into omp_drama values (1040025, '', '', '', '', '', '0', '', '', 91, 4);
insert into omp_drama values (1040026, 'omp_idle_tsun', '', '1', '', '0', '106031', '', '', 3, 4);
