insert into omp_drama values (1040028, 'vo_omp_7004_004', '', '0', '', '', 'vo_omp_7004', '', '0', 21, 4);
insert into omp_drama values (1040029, 'それはそうでございますが…\\n好奇心が勝ってしまいまして', '', '10', '', '', '105931', '1', '1', 11, 4);
insert into omp_drama values (1040030, '', '', '', '', '', '0', '', '', 91, 4);
insert into omp_drama values (1040031, '1', '', '', '', '', '105931', '', '', 4, 4);
insert into omp_drama values (1040032, 'omp_idle_worry', '', '1', '', '0', '105931', '', '', 3, 4);
