insert into omp_drama values (1040034, 'vo_omp_7004_005', '', '0', '', '', 'vo_omp_7004', '', '0', 21, 4);
insert into omp_drama values (1040035, 'コッコロちゃんの言う通りですよ！\\nさあ、決めポーズの練習をしましょう！\\nいえーい！', '', '10', '', '', '105831', '1', '1', 11, 4);
insert into omp_drama values (1040036, '1', '', '', '', '', '5.5', '', '', 93, 4);
insert into omp_drama values (1040037, 'omp_psn_11', '', '0', '', '0.2', '105831', '', '', 3, 4);
insert into omp_drama values (1040038, '', '', '', '', '', '1040035', '', '', 91, 4);
